@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_container">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public int TimeoutSeconds { get; set; } = 300;

    [Parameter] public EventCallback OnIdle { get; set; }

    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _container;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import",
                "./_content/sv-3fca4f7d28a949b58f4025d98eef4dd4/Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _container, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — nothing to clean up on the JS side.
            }
        }

        _dotNetRef?.Dispose();
    }
}

let state = null;

export function initialize(container, dotNetRef, timeoutMs) {
    let isIdle = false;
    let timer = null;

    function resetTimer() {
        clearTimeout(timer);
        timer = setTimeout(() => {
            if (!isIdle) {
                isIdle = true;
                dotNetRef.invokeMethodAsync("OnIdleCallback");
            }
        }, timeoutMs);
    }

    function onActivity() {
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }
        resetTimer();
    }

    const events = ["mousemove", "keydown", "click", "scroll"];
    for (const evt of events) {
        container.addEventListener(evt, onActivity, { passive: true });
    }

    // Also listen on the document so activity outside the container still counts.
    for (const evt of events) {
        document.addEventListener(evt, onActivity, { passive: true });
    }

    resetTimer();

    state = { container, events, onActivity, timer };
}

export function dispose() {
    if (!state) return;

    clearTimeout(state.timer);

    for (const evt of state.events) {
        state.container.removeEventListener(evt, state.onActivity);
        document.removeEventListener(evt, state.onActivity);
    }

    state = null;
}

